```class Solution {
public:
    vector<int> numsSameConsecDiff(int n, int k) {
        vector<int> result;
        for (int i = 1; i <= n; i += k) {
            int num = i;
            while (num >= 10) {
                result.push_back(num % 10);
                num /= 10;
            }
            result.push_back(num);
        }
        return result;
    }
};```

